def shift_existing_stages_and_copy_demographics(apps, schema_editor):
    Session = apps.get_model('experiment', 'Session')
    ConsentInfo = apps.get_model('experiment', 'ConsentInfo')
    DemographicInfo = apps.get_model('experiment', 'DemographicInfo')

    for consent in ConsentInfo.objects.select_related('session', 'member').all():
        if consent.age is not None or consent.gender:
            DemographicInfo.objects.get_or_create(
                session=consent.session,
                defaults={
                    'member': consent.member,
                    'age': consent.age,
                    'gender': consent.gender,
                    'ubc_student': '',
                },
            )

    Session.objects.filter(stage__gte=2).update(stage=models.F('stage') + 1)


def reverse_stage_shift(apps, schema_editor):
    Session = apps.get_model('experiment', 'Session')
    Session.objects.filter(stage__gte=3).update(stage=models.F('stage') - 1)


